module top_module(
    input d,
    input clk,
    input clr,
    input pr,
    input en,
    input sel,
    input in0,
    input in1,
    output q,
    output out
);reg invalid_q;
wire mux_out;

assign out = mux_out;

always @ (posedge clk) begin
    if (clr) begin
        invalid_q <= 0;
    end else if (pr) begin
        invalid_q <= 1;
    end else if (en) begin
        invalid_q <= d;
    end
end

assign mux_out = sel ? in1 : in0;

assign q = invalid_q;

endmodule
